// G1 — Valida resultado do HMAC + normalized_text + extraction_metadata
// SEM require(), SEM $env

const hmacResult = $input.first().json;
const webhookData = $('Webhook Trigger').first().json;
const body = webhookData.body || webhookData;

if (!hmacResult.valid) {
  throw new Error('G1_AUTH_FAILED: Assinatura HMAC inválida — ' + (hmacResult.detail || ''));
}

const { ingestion_id, project_id, normalized_text, extraction_metadata, provider_chain, callback_url } = body;

const UUID_V4_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
if (!ingestion_id || !UUID_V4_REGEX.test(ingestion_id)) {
  throw new Error('G1_INVALID: ingestion_id deve ser UUID v4');
}
if (!project_id) throw new Error('G1_INVALID: project_id ausente');
if (!normalized_text || !normalized_text.trim()) throw new Error('G1_INVALID: normalized_text vazio ou ausente');
if (normalized_text.length > 200000) throw new Error(`G1_INVALID: normalized_text excede 200000 chars (${normalized_text.length})`);
if (!extraction_metadata || typeof extraction_metadata !== 'object') throw new Error('G1_INVALID: extraction_metadata ausente');
const requiredMeta = ['source_format', 'original_size_bytes', 'normalized_char_count', 'extraction_method'];
for (const f of requiredMeta) {
  if (extraction_metadata[f] === undefined || extraction_metadata[f] === null) {
    throw new Error(`G1_INVALID: extraction_metadata.${f} ausente`);
  }
}
if (!provider_chain || !Array.isArray(provider_chain) || provider_chain.length === 0) {
  throw new Error('G1_INVALID: provider_chain ausente ou vazia');
}
if (!callback_url) throw new Error('G1_INVALID: callback_url ausente');

return [{
  json: {
    ingestion_id,
    project_id,
    normalized_text,
    extraction_metadata,
    provider_chain,
    callback_url,
    g1_validated_at: new Date().toISOString()
  }
}];

// Monta prompt para o LLM classificar o documento e decidir personas ativas
// GP é orquestrador — SEMPRE ativado automaticamente, NÃO entra em active_personas
// SEM require(), SEM $env

const item = $input.first().json;

const SYSTEM_PROMPT = `Você é o Conferente (AUD) do pipeline GCA.
Classifique o documento e decida quais especialistas analisar.

Tags disponíveis (active_personas): AUD, ARQ, DBA, DEV, QA, UX, UI, SEG, CONF, LGPD, NEG
GP NÃO entra em active_personas — é orquestrador ativado automaticamente.

Retorne JSON estrito:
{
  "doc_classification": { "primary_type": "string", "secondary_types": [], "sensitivity": "public|internal|confidential|regulated" },
  "active_personas": ["AUD", "CONF", ...],
  "shared_context": { "summary": "string", "stakeholders": [], "systems_referenced": [], "critical_dates": [] },
  "chunking_strategy": "single|section_split"
}

REGRAS:
- CONF (bloqueante) SEMPRE ativado
- AUD SEMPRE ativado
- Mínimo 3 personas em active_personas
- Código → ARQ, DEV, QA, SEG; +DBA se persistência; +UI/UX se interface
- Documento jurídico → CONF, LGPD, NEG
- Especificação funcional → ARQ, DEV, QA, UX, UI, NEG
- Em dúvida, ative mais — falso negativo custa mais que análise extra
- Retorne APENAS JSON válido, sem markdown`;

const textForClassification = item.normalized_text.substring(0, 150000);

const userMessage = JSON.stringify({
  ingestion_id: item.ingestion_id,
  source_format: item.extraction_metadata.source_format,
  char_count: item.extraction_metadata.normalized_char_count,
  extraction_warnings: item.extraction_metadata.extraction_warnings || [],
  document_text: textForClassification
}, null, 2);

return [{ json: { ...item, conferente_system_prompt: SYSTEM_PROMPT, conferente_user_message: userMessage } }];

// Extrai JSON da resposta LLM e aplica Gate G2
// GP não entra em active_personas mas é contado em expected_count (+1)
// SEM require(), SEM $env

const llmResponse = $input.first().json;
const upstream = $('Montar prompt Conferente').first().json;

let rawText = '';
if (llmResponse.content && Array.isArray(llmResponse.content)) {
  rawText = llmResponse.content.map(c => c.text || '').join('');
} else if (llmResponse.choices && Array.isArray(llmResponse.choices)) {
  rawText = llmResponse.choices[0]?.message?.content || '';
} else {
  throw new Error('G2_PARSE_FAILED: Estrutura de resposta LLM desconhecida');
}

rawText = rawText.trim();
if (rawText.startsWith('```')) {
  rawText = rawText.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
}

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  throw new Error(`G2_PARSE_FAILED: JSON inválido: ${e.message}. Trecho: ${rawText.substring(0, 200)}`);
}

// --- Gate G2 ---
const TAGS_VALIDAS = new Set(['AUD', 'ARQ', 'DBA', 'DEV', 'QA', 'UX', 'UI', 'SEG', 'CONF', 'LGPD', 'NEG']);
let activePersonas = (parsed.active_personas || []).filter(t => t !== 'GP');

if (!Array.isArray(activePersonas) || activePersonas.length === 0) {
  throw new Error('G2_INVALID: active_personas ausente ou vazio');
}
const tagsInvalidas = activePersonas.filter(t => !TAGS_VALIDAS.has(t));
if (tagsInvalidas.length > 0) {
  throw new Error(`G2_INVALID: Tags não-canônicas: ${tagsInvalidas.join(', ')}`);
}
// Garante CONF e AUD sempre presentes
if (!activePersonas.includes('CONF')) activePersonas.push('CONF');
if (!activePersonas.includes('AUD')) activePersonas.push('AUD');
// Mínimo 3
if (activePersonas.length < 3) {
  throw new Error(`G2_INVALID: active_personas deve ter mínimo 3 (recebido: ${activePersonas.length})`);
}
if (!parsed.doc_classification?.primary_type || !parsed.doc_classification?.sensitivity) {
  throw new Error('G2_INVALID: doc_classification incompleto');
}
if (!parsed.shared_context?.summary) {
  throw new Error('G2_INVALID: shared_context.summary ausente');
}

// expected_count = personas ativas + 1 (GP orquestrador)
const expectedCount = activePersonas.length + 1;

return [{
  json: {
    ingestion_id: upstream.ingestion_id,
    project_id: upstream.project_id,
    normalized_text: upstream.normalized_text,
    extraction_metadata: upstream.extraction_metadata,
    provider_chain: upstream.provider_chain,
    callback_url: upstream.callback_url,
    doc_classification: parsed.doc_classification,
    active_personas: activePersonas,
    shared_context: parsed.shared_context,
    chunking_strategy: parsed.chunking_strategy || 'single',
    expected_count: expectedCount,
    g2_validated_at: new Date().toISOString()
  }
}];

// Emite N items — 1 por persona ativa (sem GP)
// HTTP Request seguinte itera automaticamente sobre todos
// SEM require(), SEM $env

const upstream = $('Parse resposta e G2').first().json;
const {
  ingestion_id, project_id, normalized_text, extraction_metadata,
  provider_chain, callback_url, active_personas, shared_context,
  doc_classification, chunking_strategy
} = upstream;

const items = [];
for (const tag of active_personas) {
  const tagLower = tag.toLowerCase();
  const webhookUrl = `http://n8n:5678/webhook/gca-specialist-${tagLower}`;
  const payload = {
    ingestion_id, project_id, normalized_text, extraction_metadata,
    provider_chain, callback_url, shared_context, doc_classification,
    chunking_strategy, persona_tag: tag,
    dispatched_at: new Date().toISOString()
  };
  items.push({
    json: {
      webhook_url: webhookUrl,
      payload_json: JSON.stringify(payload),
      persona_tag: tag
    }
  });
}
return items;

// Prepara dispatch para o GP Orquestrador (sempre ativado)
// SEM require(), SEM $env

const upstream = $('Parse resposta e G2').first().json;

const payload = {
  ingestion_id: upstream.ingestion_id,
  project_id: upstream.project_id,
  normalized_text: upstream.normalized_text,
  extraction_metadata: upstream.extraction_metadata,
  provider_chain: upstream.provider_chain,
  callback_url: upstream.callback_url,
  doc_classification: upstream.doc_classification,
  active_personas: upstream.active_personas,
  shared_context: upstream.shared_context,
  chunking_strategy: upstream.chunking_strategy,
  persona_tag: 'GP',
  dispatched_at: new Date().toISOString()
};

return [{
  json: {
    webhook_url: 'http://n8n:5678/webhook/gca-orchestrator-gp',
    payload_json: JSON.stringify(payload),
    persona_tag: 'GP'
  }
}];

// Handler global de erro — captura falhas dos nós anteriores
// SEM require(), SEM $env

const errorData = $input.first();
const errorMessage = errorData.json.error?.message || errorData.json.message || 'Erro desconhecido no Conferente';

let ingestion_id = 'unknown';
let project_id = 'unknown';
try {
  const wh = $('Webhook Trigger').first().json;
  ingestion_id = wh.body?.ingestion_id || wh.ingestion_id || 'unknown';
  project_id = wh.body?.project_id || wh.project_id || 'unknown';
} catch (_) {}

return [{ json: { ingestion_id, project_id, error: { message: errorMessage }, failed_at: new Date().toISOString() } }];
